 1	import * as React from "react";
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  HelperText,
 6	  HelperTextItem,
 7	  ValidatedOptions,
 8	} from "@patternfly/react-core";
 9	import { useField } from "formik";
10	import { BaseInputFieldProps } from "./field-types";
11	import { useFormikValidationFix } from "../hooks/formik-validation-fix";
12	import { getFieldId } from "./field-utils";
13	import { ExclamationCircleIcon } from "@patternfly/react-icons";
14	
15	const BaseInputField: React.FC<
16	  BaseInputFieldProps & {
17	    helperIconText?: string;
18	    children: (props) => React.ReactNode;
19	  }
20	> = ({
21	  label,
22	  labelIcon,
23	  helpText,
24	  required,
25	  children,
26	  name,
27	  onChange,
28	  onBlur,
29	  helpTextInvalid,
30	  validated,
31	  ...props
32	}) => {
33	  const [field, { touched, error }] = useField({ name, type: "input" });
34	  const fieldId = getFieldId(name, "input");
35	  const isValid = !(touched && error);
36	  const errorMessage = !isValid ? error : "";
37	  useFormikValidationFix(field.value);
38	
39	  const isValidated = !isValid ? ValidatedOptions.error : validated;
40	  return (
41	    <FormGroup
42	      fieldId={fieldId}
43	      label={label}
44	      isRequired={required}
45	      labelHelp={labelHelp}
46	    >
47	      {children({
48	        ...field,
49	        ...props,
50	        value: field.value || "",
51	        id: fieldId,
52	        label,
53	        validated: isValidated,
54	        "aria-describedby": helpText ? `${fieldId}-helper` : undefined,
55	        onChange: (event, value) => {
56	          field.onChange(event);
57	          onChange && onChange(event);
58	        },
59	        onBlur: (event) => {
60	          field.onBlur(event);
61	          onBlur && onBlur(event);
62	        },
63	      })}
64	      <FormHelperText>
65	        <HelperText>
66	          <HelperTextItem
67	            variant={isValidated}
68	            {...(isValidated === "error" && {
69	              icon: <ExclamationCircleIcon />,
70	            })}
71	          >
72	            {isValidated === "error"
73	              ? errorMessage || helpTextInvalid
74	              : helpText}
75	          </HelperTextItem>
76	        </HelperText>
77	      </FormHelperText>
78	    </FormGroup>
79	  );
80	};
81	
82	export default BaseInputField;

